# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration platform that manages users, projects,
tasks, threaded messaging (with attachments), a performance dashboard, and
exportable reports (CSV / PDF).

The whole system lives in this single module and depends only on the Python
standard library.  All public read methods return deep copies so that callers
can never mutate internal state by holding on to a returned object.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Set


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not allowed to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Lock-sharing component facade
# ---------------------------------------------------------------------------
class _Component:
    """A thin namespace object that exposes the manager's shared lock.

    Every logical sub-system (users, projects, tasks, ...) is represented by
    one of these so that callers can reach the single shared lock through any
    of them, guaranteeing coarse-grained, deadlock-free synchronization.
    """

    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Central façade coordinating all collaboration features."""

    def __init__(self, now=None):
        # ``now`` is an injectable clock (a zero-arg callable returning a
        # ``datetime``).  Defaults to the wall clock.
        self._now_fn = now if callable(now) else datetime.now

        # One reentrant lock shared by every sub-component.
        self._lock = threading.RLock()

        # Global, monotonically increasing identifier counter.  Identifiers are
        # unique across *all* entity types.
        self._id_counter = 0

        # Primary stores.
        self._users: Dict[int, User] = {}
        self._projects: Dict[int, Project] = {}
        self._tasks: Dict[int, Task] = {}
        self._messages: Dict[int, Message] = {}

        # Secondary indexes.
        self._username_index: Dict[str, int] = {}
        self._email_index: Dict[str, int] = {}
        self._tasks_by_assignee: Dict[int, Set[int]] = {}
        self._ratings_by_ratee: Dict[int, List[Rating]] = {}

        # Lock-sharing facades (tested for shared-lock identity).
        self.users = _Component(self._lock)
        self.projects = _Component(self._lock)
        self.tasks = _Component(self._lock)
        self.messages = _Component(self._lock)
        self.performance = _Component(self._lock)
        self.reports = _Component(self._lock)

    # ------------------------------------------------------------------ utils
    def _now(self) -> datetime:
        return self._now_fn()

    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _clone(value):
        return copy.deepcopy(value)

    def _require_user(self, user_id: int) -> User:
        user = self._users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self._projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self._tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self._messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_username(username: str) -> str:
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")
        return username.strip()

    @staticmethod
    def _validate_email(email: str) -> str:
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("email must be a non-empty string containing '@'")
        return email

    def _set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        """Re-point a task's assignee, keeping the inverted index consistent."""
        if task.assignee_id is not None:
            bucket = self._tasks_by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    self._tasks_by_assignee.pop(task.assignee_id, None)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self._tasks_by_assignee.setdefault(new_assignee, set()).add(task.id)

    def _tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = sorted(self._tasks_by_assignee.get(user_id, set()))
        return [self._tasks[tid] for tid in ids if tid in self._tasks]

    # ------------------------------------------------------------------- users
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            uname = self._validate_username(username)
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if uname in self._username_index:
                raise DuplicateError("username {0!r} already exists".format(uname))
            if email in self._email_index:
                raise DuplicateError("email {0!r} already exists".format(email))

            user = User(
                id=self._next_id(),
                username=uname,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self._users[user.id] = user
            self._username_index[uname] = user.id
            self._email_index[email] = user.id
            return self._clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [self._clone(self._users[uid]) for uid in sorted(self._users)]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            new_username = None
            if username is not None:
                new_username = self._validate_username(username)
                owner = self._username_index.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "username {0!r} already exists".format(new_username)
                    )

            new_email = None
            if email is not None:
                new_email = self._validate_email(email)
                owner = self._email_index.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email {0!r} already exists".format(new_email))

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_username is not None:
                self._username_index.pop(user.username, None)
                user.username = new_username
                self._username_index[new_username] = user_id
            if new_email is not None:
                self._email_index.pop(user.email, None)
                user.email = new_email
                self._email_index[new_email] = user_id
            if role is not None:
                user.role = role
            return self._clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self._projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user {0} owns project {1}".format(user_id, project.id)
                    )

            for task in self._tasks.values():
                if task.assignee_id == user_id and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "user {0} has an open task {1}".format(user_id, task.id)
                    )

            self._username_index.pop(user.username, None)
            self._email_index.pop(user.email, None)
            self._tasks_by_assignee.pop(user_id, None)
            self._ratings_by_ratee.pop(user_id, None)
            del self._users[user_id]

    # ---------------------------------------------------------------- projects
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be a non-empty string")
            self._require_user(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")

            project = Project(
                id=self._next_id(),
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self._projects[project.id] = project
            return self._clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [self._clone(self._projects[pid]) for pid in sorted(self._projects)]

    def update_project(self, project_id, name=None, start_date=None, end_date=None, description=None) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name
            if name is not None:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name must be a non-empty string")
                new_name = name.strip()

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return self._clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._require_project(project_id)

            removed_task_ids = []
            for task in list(self._tasks.values()):
                if task.project_id == project_id:
                    self._set_assignee(task, None)
                    removed_task_ids.append(task.id)
                    del self._tasks[task.id]

            removed_task_set = set(removed_task_ids)
            for message in list(self._messages.values()):
                if message.project_id == project_id or message.task_id in removed_task_set:
                    del self._messages[message.id]

            del self._projects[project_id]

    # ------------------------------------------------------------------- tasks
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be a non-empty string")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot be before the project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=None,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self._tasks[task.id] = task
            if assignee_id is not None:
                self._set_assignee(task, assignee_id)
            return self._clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            tasks = [t for t in self._tasks.values() if t.project_id == project_id]
            tasks.sort(key=lambda t: t.id)
            return [self._clone(t) for t in tasks]

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            return [self._clone(t) for t in self._tasks_for_assignee(user_id)]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot be before the project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return self._clone(task)

    # ---------------------------------------------------------------- messages
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if project_id is not None:
                self._require_project(project_id)
            else:
                self._require_task(task_id)

            attachment_specs = list(attachments) if attachments else []
            if (not isinstance(body, str) or not body.strip()) and not attachment_specs:
                raise ValidationError("message must have a body or an attachment")

            if parent_id is not None and parent_id not in self._messages:
                raise NotFoundError("parent message {0} not found".format(parent_id))

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for filename, data in attachment_specs
            ]

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body if isinstance(body, str) else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self._messages[message.id] = message
            return self._clone(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            empty = not isinstance(new_body, str) or not new_body.strip()
            if empty and not message.attachments:
                raise ValidationError("message body cannot be empty")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be a non-empty string")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                )
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            msgs = [m for m in self._messages.values() if m.project_id == project_id]
            msgs.sort(key=lambda m: m.id)
            return [self._clone(m) for m in msgs]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            msgs = [m for m in self._messages.values() if m.task_id == task_id]
            msgs.sort(key=lambda m: m.id)
            return [self._clone(m) for m in msgs]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            del self._messages[message_id]

    # ------------------------------------------------------------- performance
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(self._tasks_for_assignee(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool) or score < 1 or score > 5:
                raise ValidationError("score must be an integer between 1 and 5")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rating)
            return self._clone(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_by_ratee.get(user_id, [])
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            durations = self._completion_durations(tasks)
            avg_time = sum(durations) / len(durations) if durations else None

            ratings = self._ratings_by_ratee.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ----------------------------------------------------------------- reports
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self._require_project(project_id)
            tasks = [t for t in self._tasks.values() if t.project_id == project_id]
            now = self._now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.status != TaskStatus.COMPLETED
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0, "in_progress": 0, "not_started": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1
                    elif task.status == TaskStatus.IN_PROGRESS:
                        bucket["in_progress"] += 1
                    else:
                        bucket["not_started"] += 1

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scoped = [t for t in self._tasks.values() if t.project_id == project_id]
            else:
                scoped = list(self._tasks.values())

            by_user: Dict[int, List[Task]] = {}
            for task in scoped:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                user = self._users.get(user_id)
                if user is None:
                    continue
                rows.append(self._performance_row(user, by_user[user_id]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def _performance_row(self, user: User, tasks: List[Task]) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = self._completion_durations(tasks)
        avg_time = sum(durations) / len(durations) if durations else None
        ratings = self._ratings_by_ratee.get(user.id, [])
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        return {
            "user_id": user.id,
            "username": user.username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            durations = self._completion_durations(tasks)
            avg_time = sum(durations) / len(durations) if durations else None
            ratings = self._ratings_by_ratee.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [self._clone(t) for t in tasks],
            }

    # ------------------------------------------------------------ exporting
    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")

        header, rows = self._report_table(report)
        if report_format == ReportFormat.CSV:
            return self._render_csv(header, rows)
        return self._render_pdf(report, header, rows)

    @staticmethod
    def _fmt(value) -> str:
        if value is None:
            return ""
        if isinstance(value, datetime):
            return value.isoformat()
        if isinstance(value, Enum):
            return value.value
        return str(value)

    def _report_table(self, report):
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            rows = [[row.get(key) for key in header] for row in report.get("rows", [])]
            return header, rows

        if report_type == ReportType.PROJECT_PROGRESS.value:
            header = ["field", "value"]
            rows = [
                ["project_id", report.get("project_id")],
                ["total_tasks", report.get("total_tasks")],
                ["completion_rate", report.get("completion_rate")],
                ["overdue_tasks", report.get("overdue_tasks")],
            ]
            for status, count in report.get("status_counts", {}).items():
                rows.append(["status_{0}".format(status), count])
            return header, rows

        if report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "task_id", "title", "status", "assignee_id",
                "deadline", "started_at", "completed_at",
            ]
            rows = []
            for task in report.get("tasks", []):
                rows.append([
                    task.id,
                    task.title,
                    self._fmt(task.status),
                    task.assignee_id,
                    self._fmt(task.deadline),
                    self._fmt(task.started_at),
                    self._fmt(task.completed_at),
                ])
            return header, rows

        # Generic fall-back: emit a flat key/value table for any other dict.
        header = ["field", "value"]
        rows = [[key, repr(value)] for key, value in report.items()]
        if not rows:
            rows = [["report", repr(report)]]
        return header, rows

    @staticmethod
    def _render_csv(header, rows) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        writer.writerow(header)
        for row in rows:
            writer.writerow(["" if cell is None else cell for cell in row])
        return buffer.getvalue()

    def _render_pdf(self, report, header, rows) -> bytes:
        title = "Report: {0}".format(report.get("report_type", "report"))
        lines = [title, ""]
        lines.append(" | ".join(str(col) for col in header))
        for row in rows:
            lines.append(" | ".join("" if cell is None else str(cell) for cell in row))
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(text_lines) -> bytes:
        """Construct a minimal but structurally valid single-page PDF."""
        content_ops = ["BT", "/F1 12 Tf", "1 0 0 1 50 740 Tm", "16 TL"]
        for index, line in enumerate(text_lines):
            safe = (
                str(line)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )
            if index == 0:
                content_ops.append("({0}) Tj".format(safe))
            else:
                content_ops.append("T* ({0}) Tj".format(safe))
        content_ops.append("ET")
        content = "\n".join(content_ops).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
            b"<< /Length " + str(len(content)).encode("ascii") + b" >>\nstream\n"
            + content + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(number).encode("ascii")
            pdf += body
            pdf += b"\nendobj\n"

        xref_position = len(pdf)
        count = len(objects) + 1
        pdf += "xref\n0 {0}\n".format(count).encode("ascii")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF".format(
            count, xref_position
        ).encode("ascii")
        return bytes(pdf)


